#endif

#if defined(__APPLE__)
.macro _makesym name, base, len
.set \name, cake_main+\base
.endm
# define makesym(name,base,len) _makesym name, base, len
#elif defined(__WIN32)
.macro _makesym name, base, len
.set \name, cake_main+\base
.endm
# define makesym(name,base,len) _makesym name, base, len
#else
.macro _makesym name, base, len
.local \name
.set \name, cake_main+\base
.size \name, \len
.type \name, function
.endm
# define makesym(name,base,len) _makesym name, base, len
#endif

