windows_ffiget_arg_length:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiget_arg_length)

windows_ffiget_arg:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiget_arg)

windows_ffiget_arg_count:
