     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiget_arg_count)

windows_ffiwrite:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiwrite)

windows_ffiopen_in:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
