     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(cml_clear)
windows_cml_exit:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     callq   cdecl(cml_exit)
